(() => {
  const body = $('Webhook').item.json.body || {};
  const attachments = body.attachments || [];
  const text = (body.content || "").trim();

  const hasText = text.length > 0;
  const hasAttachment = attachments.length > 0;
  const mediaType = hasAttachment
    ? (attachments[0].file_type || "attachment").toLowerCase()
    : "none";

  if (hasAttachment && hasText) return `${mediaType}_with_text`;
  if (hasAttachment) return `${mediaType}_only`;
  if (hasText) return "text_only";

  return "unknown";
})()
}}

