const original = $('Mensagem').first().json;
const currentMessageId = Number(original.message_id);

const root = $input.first().json;
const messages = Array.isArray(root.payload) ? root.payload : [];

// Chatwoot:
// 0 = incoming do lead
// 1 = outgoing da Julia/agente
const incoming = messages
  .filter(m => Number(m.message_type) === 0)
  .sort((a, b) => Number(a.id) - Number(b.id));

if (!incoming.length) {
  return [
    {
      json: {
        should_reply: true,
        used_fallback: true,
        latest_incoming_id: currentMessageId,
        current_message_id: currentMessageId,
        all_incoming: [
          {
            id: currentMessageId,
            content: original.content || '',
            created_at: original.created_at || null,
            message_type: 0
          }
        ],
        conversation_id: original.conversation_id,
        account_id: original.account_id,
        contact_id: root.meta?.contact?.id || null,
        contact_name: root.meta?.contact?.name || '',
        lead_status: root.meta?.contact?.custom_attributes?.status || '',
        lead_summary: root.meta?.contact?.custom_attributes?.lead_summary || '',
        last_intent: root.meta?.contact?.custom_attributes?.last_intent || ''
      }
    }
  ];
}

// se a última incoming encontrada depois da busca
// ainda for a própria mensagem atual, essa execução responde
const latestIncoming = incoming[incoming.length - 1];

return [
  {
    json: {
      should_reply: Number(latestIncoming.id) === currentMessageId,
      used_fallback: false,
      latest_incoming_id: Number(latestIncoming.id),
      current_message_id: currentMessageId,
      all_incoming: incoming,
      conversation_id: original.conversation_id,
      account_id: original.account_id,
      contact_id: root.meta?.contact?.id || null,
      contact_name: root.meta?.contact?.name || '',
      lead_status: root.meta?.contact?.custom_attributes?.status || '',
      lead_summary: root.meta?.contact?.custom_attributes?.lead_summary || '',
      last_intent: root.meta?.contact?.custom_attributes?.last_intent || ''
    }
  }
];

const original = $('Devo responder?').first().json;
const currentMessageId = Number(original.current_message_id);

const root = $input.first().json;
const messages = Array.isArray(root.payload) ? root.payload : [];

// ordenar por id crescente
messages.sort((a, b) => Number(a.id) - Number(b.id));

// vamos pegar a sequência final de mensagens do lead
const grouped = [];

// encontrar o índice da mensagem atual
const currentIndex = messages.findIndex(m => Number(m.id) === currentMessageId);

if (currentIndex === -1) {
  return [
    {
      json: {
        merged_lead_message: original.message || '',
        grouped_message_ids: [currentMessageId],
        conversation_id: original.conversation_id,
        contact_id: original.contact_id,
        lead_status: original.lead_status || '',
        lead_summary: original.lead_summary || '',
        last_intent: original.last_intent || ''
      }
    }
  ];
}

// andar para trás a partir da mensagem atual
for (let i = currentIndex; i >= 0; i--) {
  const msg = messages[i];
  const type = Number(msg.message_type);

  if (type === 0) {
    grouped.unshift(msg); // incoming do lead
  } else {
    // se encontrou outgoing ou system antes do bloco atual, para
    if (grouped.length > 0) break;
  }
}

const mergedText = grouped
  .map(m => (m.content || '').trim())
  .filter(Boolean)
  .join('\n');

return [
  {
    json: {
      merged_lead_message: mergedText || original.message || '',
      grouped_message_ids: grouped.map(m => m.id),
      conversation_id: original.conversation_id,
      contact_id: original.contact_id,
      lead_status: original.lead_status || '',
      lead_summary: original.lead_summary || '',
      last_intent: original.last_intent || ''
    }
  }
];

