const itemsOut = [];

function clean(val) {
  if (val === undefined || val === null) return null;
  const s = String(val).trim();
  return s === '' ? null : s;
}

function normalizePhone(phone) {
  if (!phone) return null;
  const digits = String(phone).replace(/\D+/g, '');
  return digits || null;
}

function extractField(text, labels) {
  for (const label of labels) {
    const regex = new RegExp(
      `${label}\\s*:\\s*([^\\n\\r|]+)`,
      'i'
    );
    const match = text.match(regex);
    if (match && match[1]) return clean(match[1]);
  }
  return null;
}

function extractInstagram(text) {
  const empresa = extractField(text, ['empresa', 'instagram', 'insta', 'ig']);
  if (empresa && empresa.startsWith('@')) return empresa;

  const atMatch = text.match(/(^|\s)(@[a-zA-Z0-9._]{3,})\b/);
  if (atMatch && atMatch[2]) return clean(atMatch[2]);

  const igUrl = text.match(/https?:\/\/(www\.)?instagram\.com\/([a-zA-Z0-9._]+)/i);
  if (igUrl && igUrl[2]) return '@' + igUrl[2];

  return null;
}

function buildLeadSummary(currentSummary, parsed) {
  const fields = {
    'Nome': parsed.name,
    'Empresa': parsed.empresa,
    'Nicho': parsed.nicho,
    'Serviço de interesse': parsed.servico_interesse,
    'Objetivo': parsed.objetivo,
    'Canal atual': parsed.canal_atual,
    'Vende por': parsed.vende_por,
    'Equipe': parsed.funcionarios,
    'Investimento': parsed.investimento,
    'Instagram': parsed.instagram,
    'Site': parsed.site,
    'Google Meu Negócio': parsed.google_meu_negocio,
    'Momento': parsed.momento,
    'Objeções': parsed.objecoes,
    'Último contexto': parsed.ultimo_contexto,
    'Próxima etapa': parsed.proxima_etapa,
  };

  const existing = {};
  if (currentSummary) {
    const parts = String(currentSummary).split(';');
    for (const part of parts) {
      const idx = part.indexOf(':');
      if (idx > -1) {
        const k = part.slice(0, idx).trim();
        const v = part.slice(idx + 1).trim();
        if (k) existing[k] = v;
      }
    }
  }

  for (const [k, v] of Object.entries(fields)) {
    if (v !== null && v !== undefined && String(v).trim() !== '') {
      existing[k] = String(v).trim();
    }
  }

  return Object.entries(existing)
    .map(([k, v]) => `${k}: ${v}`)
    .join('; ');
}

for (const item of items) {
  const json = item.json;

  const rawMessage =
    json.message ||
    json.body ||
    json.content ||
    json.text ||
    json.last_user_message ||
    '';

  const text = String(rawMessage);

  const name =
    clean(json.name) ||
    clean(json.sender_name) ||
    extractField(text, ['nome', 'name']);

  const empresa =
    clean(json.empresa) ||
    extractField(text, ['empresa', 'negócio', 'negocio', 'marca']);

  const telefone =
    normalizePhone(json.phone) ||
    normalizePhone(extractField(text, ['telefone', 'phone', 'whatsapp', 'fone']));

  const investimento =
    clean(json.investimento) ||
    extractField(text, ['investe', 'investimento', 'tráfego', 'trafego']);

  const funcionarios =
    clean(json.funcionarios) ||
    extractField(text, ['funcionários', 'funcionarios', 'equipe', 'colaboradores']);

  const instagram =
    clean(json.instagram) ||
    extractInstagram(text) ||
    (empresa && empresa.startsWith('@') ? empresa : null);

  const site =
    clean(json.site) ||
    extractField(text, ['site', 'website']) ||
    (text.match(/https?:\/\/[^\s]+/i)?.[0] || null);

  const googleMeuNegocio =
    clean(json.google_meu_negocio) ||
    extractField(text, ['google meu negócio', 'google meu negocio', 'gmn', 'google business']);

  const parsed = {
    name,
    empresa,
    telefone,
    investimento,
    funcionarios,
    instagram,
    site,
    google_meu_negocio: googleMeuNegocio,
    nicho: clean(json.nicho) || null,
    servico_interesse: clean(json.servico_interesse) || 'Tráfego pago',
    objetivo: clean(json.objetivo) || null,
    canal_atual: clean(json.canal_atual) || null,
    vende_por: clean(json.vende_por) || null,
    momento: clean(json.momento) || null,
