const original = $('Mensagem').first().json;
const currentMessageId = Number(original.message_id);

const root = $input.first().json;
const messages = Array.isArray(root.payload) ? root.payload : [];

// Chatwoot:
// 0 = incoming do lead
// 1 = outgoing da Julia/agente
const incoming = messages
  .filter(m => Number(m.message_type) === 0)
  .sort((a, b) => Number(a.id) - Number(b.id));

if (!incoming.length) {
  return [
    {
      json: {
        should_reply: true,
        used_fallback: true,
        latest_incoming_id: currentMessageId,
        current_message_id: currentMessageId,
        all_incoming: [
          {
            id: currentMessageId,
            content: original.content || '',
            created_at: original.created_at || null,
            message_type: 0
          }
        ],
        conversation_id: original.conversation_id,
        account_id: original.account_id,
        contact_id: root.meta?.contact?.id || null,
        contact_name: root.meta?.contact?.name || '',
        lead_status: root.meta?.contact?.custom_attributes?.status || '',
        lead_summary: root.meta?.contact?.custom_attributes?.lead_summary || '',
        last_intent: root.meta?.contact?.custom_attributes?.last_intent || ''
      }
    }
  ];
}

// se a última incoming encontrada depois da busca
// ainda for a própria mensagem atual, essa execução responde
const latestIncoming = incoming[incoming.length - 1];

return [
  {
    json: {
      should_reply: Number(latestIncoming.id) === currentMessageId,
      used_fallback: false,
      latest_incoming_id: Number(latestIncoming.id),
      current_message_id: currentMessageId,
      all_incoming: incoming,
      conversation_id: original.conversation_id,
      account_id: original.account_id,
      contact_id: root.meta?.contact?.id || null,
      contact_name: root.meta?.contact?.name || '',
      lead_status: root.meta?.contact?.custom_attributes?.status || '',
      lead_summary: root.meta?.contact?.custom_attributes?.lead_summary || '',
      last_intent: root.meta?.contact?.custom_attributes?.last_intent || ''
    }
  }
];

